class Solution {
    public int kIncreasing(int[] arr, int k) {
        int n = arr.length;
        int res = 0;
        for (int i = 0; i < k; i++) {
            int[] sub = new int[(n - i - 1) / k + 1];
            int idx = 0;
            for (int j = i; j < n; j += k) {
                sub[idx++] = arr[j];
            }
            int[] lis = new int[sub.length];
            int len = 0;
            for (int num : sub) {
                int pos = binarySearch(lis, len, num);
                lis[pos] = num;
                if (pos == len) len++;
            }
            res += sub.length - len;
        }
        return res;
    }

    private int binarySearch(int[] lis, int len, int num) {
        int left = 0, right = len;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (lis[mid] < num) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
}
